#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=1e5+5;
int n,q,cnt[MAXN];
string s;
struct node
{
    bool color;
    int l,r;
}tree[MAXN];
void dfs(int x,int k)
{
	int p=k+cnt[x];
	if(p&1)
    {
        tree[x].color=!tree[x].color;
    }
	if(tree[x].l)
    {
        dfs(tree[x].l,p);
    }
	if(tree[x].r)
    {
        dfs(tree[x].r,p);
    }
}
int main(void)
{
	n=read();
	for(int i=1,tmp;i<n;++i)
    {
        tmp=read();
		if(tree[tmp].l!=0)tree[tmp].r=i+1;
		else tree[tmp].l=i+1;
	}
	cin>>s;
	for(int i=0;i<s.size();++i)
    {
        tree[i+1].color=bool(s[i]-'0');
    }
    q=read();
	for(int i=1;i<=q;++i)
    {
        ++cnt[read()];
    }
    dfs(1,0);
	for(int i=1;i<=n;++i)
    {
        write(int(tree[i].color));
    }
	return false;
}
